extra.modelCss:
/* Tipografia base profissional */

:root {
  --text: #111827;
  --muted: #6b7280;
}

body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  color: var(--text);
  line-height: 1.6;
}

h1 {
  font-size: 2.25rem;
  line-height: 1.2;
  font-weight: 700;
}

h2 {
  font-size: 1.5rem;
  line-height: 1.25;
  font-weight: 600;
}

p {
  font-size: 1rem;
}

.small {
  font-size: 0.875rem;
  color: var(--muted);
}

.prose {
  max-width: 65ch;
}

.label {
  font-size: 0.75rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}
